1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Damage = { itemType: string; amount: number };
10	
11	export type ClaimStep = {
12	  kind: "claim";
13	  policy: number;
14	  incident: { cause?: string; damages: Damage[] };
15	};
16	
17	export type Step = QuoteStep | ClaimStep;
18	
19	export type Customer = { yearsWithMHPCO: number };
20	
21	export type Scenario = {
22	  customer: Customer;
23	  steps: Step[];
24	};
25	
26	export type ScenarioResult = {
27	  results: unknown[];
28	};
29	
30	const COMPONENT_BASE_PREMIUM = 25;
31	
32	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: COMPONENT_BASE_PREMIUM,
38	  moonstone: COMPONENT_BASE_PREMIUM,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
43	const LOYALTY_DISCOUNT_RATE = 0.2;
44	const LOYALTY_THRESHOLD_YEARS = 2;
45	const PROCESSING_FEE = 5;
46	
47	const CURSED_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	
51	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
52	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
53	const DEDUCTIBLE = 100;
54	
55	function isCursed(item: Item): boolean {
56	  return item.cursed === true;
57	}
58	
59	function isHighlyEnchanted(item: Item): boolean {
60	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
61	}
62	
63	function riskMultiplierForItem(item: Item): number {
64	  return (
65	    1 +
66	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
67	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
68	  );
69	}
70	
71	function basePremiumForItem(item: Item): number {
72	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
73	}
74	
75	type QuoteResult = { kind: "quote"; premium: number };
76	type ClaimResult = { kind: "claim"; payout: number };
77	type StepResult = QuoteResult | ClaimResult;
78	
79	function reimbursementForDamage(damage: Damage, policy: QuoteStep): number {
80	  const item = policy.items.find((i) => i.kind === damage.itemType);
81	  if (item === undefined) return 0;
82	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
83	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
84	  }
85	  return 0;
86	}
87	
88	function claimStep(step: ClaimStep, policy: QuoteStep): ClaimResult {
89	  const reimbursable = step.incident.damages.reduce(
90	    (sum, damage) => sum + reimbursementForDamage(damage, policy),
91	    0,
92	  );
93	  const payout = Math.max(0, reimbursable - DEDUCTIBLE);
94	  return { kind: "claim", payout };
95	}
96	
97	const BUILDING_BLOCK_BASE_PREMIUM = 60;
98	const BUILDING_BLOCK_SIZE = 3;
99	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
100	
101	type ItemGroup = { kind: Item["kind"]; items: Item[] };
102	
103	function groupByKind(items: Item[]): ItemGroup[] {
104	  const groups = new Map<Item["kind"], Item[]>();
105	  for (const item of items) {
106	    const group = groups.get(item.kind) ?? [];
107	    group.push(item);
108	    groups.set(item.kind, group);
109	  }
110	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
111	}
112	
113	function isComponentKind(kind: Item["kind"]): boolean {
114	  return COMPONENT_KINDS.includes(kind);
115	}
116	
117	function isBuildingBlock(group: ItemGroup): boolean {
118	  return group.items.length === BUILDING_BLOCK_SIZE && isComponentKind(group.kind);
119	}
120	
121	function basePremiumForGroup(group: ItemGroup): number {
122	  if (isBuildingBlock(group)) {
123	    return BUILDING_BLOCK_BASE_PREMIUM;
124	  }
125	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
126	}
127	
128	function basePremiumForItems(items: Item[]): number {
129	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
130	}
131	
132	function contractSequenceRate(contractIndex: number): number {
133	  return contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
134	}
135	
136	function loyaltyRate(customer: Customer): number {
137	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
138	}
139	
140	function customerRateForContract(
141	  contractIndex: number,
142	  customer: Customer,
143	): number {
144	  return contractSequenceRate(contractIndex) + loyaltyRate(customer);
145	}
146	
147	function quoteStep(
148	  step: QuoteStep,
149	  contractIndex: number,
150	  customer: Customer,
151	): QuoteResult {
152	  const basePremium = basePremiumForItems(step.items);
153	  const customerAdjustment = basePremium * customerRateForContract(contractIndex, customer);
154	  const premium = Math.ceil(basePremium + customerAdjustment + PROCESSING_FEE);
155	  return { kind: "quote", premium };
156	}
157	
158	function processStep(
159	  step: Step,
160	  contractIndex: number,
161	  customer: Customer,
162	  steps: Step[],
163	): StepResult {
164	  if (step.kind === "quote") {
165	    return quoteStep(step, contractIndex, customer);
166	  }
167	  return claimStep(step, steps[step.policy] as QuoteStep);
168	}
169	
170	function countQuotesBefore(steps: Step[], index: number): number {
171	  return steps.slice(0, index).filter((step) => step.kind === "quote").length;
172	}
173	
174	export function processScenario(scenario: Scenario): ScenarioResult {
175	  const results = scenario.steps.map((step, index) =>
176	    processStep(step, countQuotesBefore(scenario.steps, index), scenario.customer, scenario.steps),
177	  );
178	  return { results };
179	}
